import { defineConfig } from "@trigger.dev/sdk";

export default defineConfig({
  project: "progress-project",
  runtime: "node",
  triggerDirectories: ["./trigger"],
});

import { defineConfig } from "@trigger.dev/sdk";

export default defineConfig({
  project: "progress-project",
  runtime: "node",
  triggerDirectories: ["./trigger"],
});

import { metadata, task, wait } from "@trigger.dev/sdk";

const trialId = "realtime_progress_metadata__Jmng4Pv";

export const progressTask = task({
  id: `progressTask-${trialId}`,
  run: async () => {
    const totalItems = 10;

    for (let index = 1; index <= totalItems; index += 1) {
      const percentage = Math.round((index / totalItems) * 100);

      metadata.set("progress", percentage);
      metadata.append("logs", `Processed item ${index} of ${totalItems}`);

      await wait.for({ seconds: 1 });
    }

    return {
      processedItems: totalItems,
    };
  },
});

